INSERT INTO "tags" ("name", "mitre_id", "tactic", "description", "is_system")
VALUES
  ('Asynchronous Procedure Call', 'T1055.004', 'Defense Evasion, Privilege Escalation', 'Adversaries may inject malicious code into processes via the asynchronous procedure call (APC) queue in order to evade process-based defenses as well as possibly elevate privileges.', true),
